const express = require('express');
const session = require('express-session');
const axios = require('axios');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');

const app = express();

const PORT = process.env.PORT || 3000;

const OIDC_ISSUER = process.env.OIDC_ISSUER || 'https://example-issuer.com';
const OIDC_AUTHORIZATION_ENDPOINT = process.env.OIDC_AUTHORIZATION_ENDPOINT || `${OIDC_ISSUER}/authorize`;
const OIDC_TOKEN_ENDPOINT = process.env.OIDC_TOKEN_ENDPOINT || `${OIDC_ISSUER}/token`;
const OIDC_CLIENT_ID = process.env.OIDC_CLIENT_ID || 'your-client-id';
const OIDC_CLIENT_SECRET = process.env.OIDC_CLIENT_SECRET || 'your-client-secret';
const OIDC_REDIRECT_URI = process.env.OIDC_REDIRECT_URI || `http://localhost:${PORT}/auth/callback`;
const SESSION_SECRET = process.env.SESSION_SECRET || 'replace-with-a-strong-secret';

app.use(
  session({
    secret: SESSION_SECRET,
    resave: false,
    saveUninitialized: false,
    cookie: {
      httpOnly: true,
      sameSite: 'lax',
      secure: false
    }
  })
);

function base64UrlEncode(buffer) {
  return buffer
    .toString('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
}

function generateState() {
  return base64UrlEncode(crypto.randomBytes(32));
}

function generateNonce() {
  return base64UrlEncode(crypto.randomBytes(32));
}

app.get('/login', (req, res) => {
  const state = generateState();
  const nonce = generateNonce();

  req.session.oidcState = state;
  req.session.oidcNonce = nonce;

  const params = new URLSearchParams({
    response_type: 'code',
    client_id: OIDC_CLIENT_ID,
    redirect_uri: OIDC_REDIRECT_URI,
    scope: 'openid email profile',
    state,
    nonce
  });

  res.redirect(`${OIDC_AUTHORIZATION_ENDPOINT}?${params.toString()}`);
});

app.get('/auth/callback', async (req, res) => {
  try {
    const { code, state, error, error_description } = req.query;

    if (error) {
      return res.status(400).json({ error, error_description: error_description || null });
    }

    if (!code) {
      return res.status(400).json({ error: 'missing_authorization_code' });
    }

    if (!state || state !== req.session.oidcState) {
      return res.status(400).json({ error: 'invalid_state' });
    }

    const tokenResponse = await axios.post(
      OIDC_TOKEN_ENDPOINT,
      new URLSearchParams({
        grant_type: 'authorization_code',
        code: String(code),
        redirect_uri: OIDC_REDIRECT_URI,
        client_id: OIDC_CLIENT_ID,
        client_secret: OIDC_CLIENT_SECRET
      }).toString(),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        }
      }
    );

    const { access_token, id_token, refresh_token, expires_in, token_type } = tokenResponse.data || {};

    if (!id_token) {
      return res.status(400).json({ error: 'missing_id_token' });
    }

    const decoded = jwt.decode(id_token, { complete: true });

    if (!decoded || !decoded.payload) {
      return res.status(400).json({ error: 'invalid_id_token' });
    }

    const claims = decoded.payload;

    if (req.session.oidcNonce && claims.nonce !== req.session.oidcNonce) {
      return res.status(400).json({ error: 'invalid_nonce' });
    }

    const user = {
      sub: claims.sub || null,
      email: claims.email || null,
      name: claims.name || null
    };

    req.session.user = user;
    req.session.tokens = {
      access_token: access_token || null,
      id_token: id_token || null,
      refresh_token: refresh_token || null,
      expires_in: expires_in || null,
      token_type: token_type || null
    };
    req.session.authenticated = true;

    delete req.session.oidcState;
    delete req.session.oidcNonce;

    res.json({
      message: 'authenticated',
      user
    });
  } catch (err) {
    const status = err.response?.status || 500;
    const data = err.response?.data || { error: 'authentication_failed', message: err.message };
    res.status(status).json(data);
  }
});

app.get('/me', (req, res) => {
  if (!req.session.authenticated || !req.session.user) {
    return res.status(401).json({ error: 'unauthenticated' });
  }

  res.json({
    authenticated: true,
    user: req.session.user
  });
});

app.get('/logout', (req, res) => {
  req.session.destroy(() => {
    res.json({ message: 'logged_out' });
  });
});

